import classnames from 'classnames';
import PropTypes from 'prop-types';
import React from 'react';
import variables from '../CodeWindow.module.scss';
import styles from './CodeBlock.module.scss';

const CodeBlock = ({ blockType, currentSize, isActiveBlock, hasColorStyle }) => {
  const classNames = classnames(
    blockType,
    { [styles.active]: isActiveBlock },
    { [styles.color]: hasColorStyle }
  );

  // calculate the width to make sure blocks in separate lines perfectly align
  const calculatedWidth = `calc(${variables.codeBlockSize} * ${currentSize})`;
  const calculatedSpace = `calc(${variables.codeLineSpace} * ${currentSize * 2 - 2})`;
  const style = currentSize > 1 ? { width: `calc(${calculatedWidth} + ${calculatedSpace})` } : null;

  return <div className={classNames} style={style} />;
};

CodeBlock.propTypes = {
  blockType: PropTypes.string.isRequired,
  currentSize: PropTypes.number.isRequired,
  isActiveBlock: PropTypes.bool.isRequired,
  hasColorStyle: PropTypes.bool.isRequired
};

export default CodeBlock;
